# Generated by prepare_cd38_external_tool_inputs.py
# Refresh CD38 readiness after external tools finish.
$ErrorActionPreference = 'Stop'
$PackageRoot = Split-Path -Parent $MyInvocation.MyCommand.Path

$RepoRoot = Resolve-Path (Join-Path $PackageRoot "..\..\..")
$P2RankRoot = Join-Path $PackageRoot "p2rank_outputs"
$FpocketRoot = Join-Path $PackageRoot "fpocket_runs"
Push-Location $RepoRoot
try {
  python refresh_cd38_benchmark_readiness.py --p2rank_root $P2RankRoot --fpocket_root $FpocketRoot --chain_filter A --rank_by_pdb "3ROP=2,4OGW=1"
} finally {
  Pop-Location
}
